class Pre(BaseModel):
    is_safe: bool
    is_in_scope: bool
    rationale: str

pre = haiku_check(user_input)
if not pre.is_safe or not pre.is_in_scope:
    return canned_refusal(pre.rationale)

# only here do we burn the strong model
return sonnet_handle(user_input)

